import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return 5 G premium for an empty item list (processing fee only)");
    it.todo("should return base premium plus fee for a single plain sword");
    it.todo("should return base premium plus fee for a single plain amulet");
    it.todo("should combine base premiums plus fee for multiple plain items");
    it.todo("should add 50% cursed surcharge on the affected item's base premium");
    it.todo("should add 30% high-enchantment surcharge for items with enchantment >= 5");
    it.todo("should add both cursed and high-enchantment surcharges when both apply");
    it.todo("should price each component (rune) at 25 G base premium");
    it.todo("should apply a block rate of 60 G for exactly 3 identical components");
    it.todo("should not apply the block rate when 4 or more identical components are present");
    it.todo("should apply the block rate separately for each group of 3 identical alike components");
    it.todo("should apply 20% loyalty discount on policy base premium for customers with >= 2 years");
    it.todo("should apply 10% first-insurance surcharge on policy base premium");
    it.todo("should apply 15% follow-up discount on policy base premium for second-or-later quotes");
    it.todo("should round the final premium up (in MHPCO's favor)");
  });

  describe("claim", () => {
    it.todo("should pay damage minus 100 G deductible for a standard item");
    it.todo("should pay 50% of damage minus deductible for items with enchantment >= 8");
    it.todo("should pay full damage minus deductible for dragon-material items");
    it.todo("should apply the 50% rule (not full reimbursement) when both dragon material and high enchantment apply");
    it.todo("should cap the payout at twice the policy insurance sum");
    it.todo("should reduce the remaining cap after each claim");
    it.todo("should round the final payout down (in MHPCO's favor)");
  });
});

