const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  rune: 25,
};

const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 100;

export const quote = (
  customer: unknown,
  items: unknown[],
  isFirstQuote?: boolean
): number => {
  const typedItems = items as { type: string; cursed?: boolean; enchantment?: number }[];
  const { policyBase, curseSurcharges, enchantSurcharges } = typedItems.reduce(
    (acc, item) => {
      const base = basePremiumFor(item.type);
      return {
        policyBase: acc.policyBase + base,
        curseSurcharges: acc.curseSurcharges + (item.cursed ? base * 0.5 : 0),
        enchantSurcharges: acc.enchantSurcharges + ((item.enchantment ?? 0) >= 5 ? base * 0.3 : 0),
      };
    },
    { policyBase: 0, curseSurcharges: 0, enchantSurcharges: 0 }
  );
  const premiumBeforeFee = policyBase + curseSurcharges + enchantSurcharges + policyBase * 0.1;
  return premiumBeforeFee + PROCESSING_FEE;
};

export const claim = (
  customer: unknown,
  policy: unknown,
  incident: unknown
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

