const PROCESSING_FEE = 5;
const BLOCK_QUANTITY = 3;
const BLOCK_RATE = 60;
const CURSE_SURCHARGE_RATE = 0.5;
const ENCHANT_SURCHARGE_RATE = 0.3;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  rune: 25,
};

const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 100;

export const quote = (
  customer: unknown,
  items: unknown[],
  isFirstQuote?: boolean
): number => {
  const typedItems = items as { type: string; cursed?: boolean; enchantment?: number }[];
  const typeCounts = typedItems.reduce<Record<string, number>>(
    (acc, item) => ({ ...acc, [item.type]: (acc[item.type] ?? 0) + 1 }),
    {}
  );
  const policyBase = Object.entries(typeCounts).reduce(
    (sum, [type, count]) => sum + (count === BLOCK_QUANTITY ? BLOCK_RATE : count * basePremiumFor(type)),
    0
  );
  const { curseSurcharges, enchantSurcharges } = typedItems.reduce(
    (acc, item) => {
      const base = basePremiumFor(item.type);
      return {
        curseSurcharges: acc.curseSurcharges + (item.cursed ? base * CURSE_SURCHARGE_RATE : 0),
        enchantSurcharges: acc.enchantSurcharges + ((item.enchantment ?? 0) >= 5 ? base * ENCHANT_SURCHARGE_RATE : 0),
      };
    },
    { curseSurcharges: 0, enchantSurcharges: 0 }
  );
  const typedCustomer = customer as { yearsWithMHPCO: number };
  const loyaltyDiscount = typedCustomer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
  const firstInsuranceSurcharge = policyBase * 0.1;
  const premiumBeforeFee = policyBase + curseSurcharges + enchantSurcharges + firstInsuranceSurcharge - loyaltyDiscount;
  return premiumBeforeFee + PROCESSING_FEE;
};

export const claim = (
  customer: unknown,
  policy: unknown,
  incident: unknown
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

